  1	/* Pico.css provides base styling - only custom additions needed */
  2	
  3	main {
  4	  max-width: 52rem;
  5	  margin: 0 auto;
  6	}
  7	
  8	.prompt-row {
  9	  display: block;
 10	  padding: 0.75rem 0;
 11	  border-bottom: 1px solid #ddd;
 12	}
 13	
 14	.prompt-row .name {
 15	  font-family: ui-monospace, monospace;
 16	  font-weight: bold;
 17	}
 18	
 19	.prompt-row textarea {
 20	  width: 100%;
 21	  font-family: ui-monospace, monospace;
 22	  margin: 0.5rem 0;
 23	}
 24	
 25	.actions {
 26	  display: flex;
 27	  gap: 0.5rem;
 28	}
 29	
 30	.add {
 31	  margin-top: 1.5rem;
 32	  padding-top: 1rem;
 33	  border-top: 1px solid #ccc;
 34	}
 35	
 36	.title-row {
 37	  display: flex;
 38	  align-items: center;
 39	  gap: 0.5rem;
 40	  flex-wrap: wrap;
 41	}
 42	
 43	.title-input {
 44	  flex: 1;
 45	  min-width: 200px;
 46	}
 47	
 48	.error {
 49	  color: #a22;
 50	  margin: 0.5rem 0;
 51	}
 52	
 53	.success {
 54	  color: #2a2;
 55	  margin: 0.5rem 0;
 56	}
 57	
 58	/* htmx loading indicator */
 59	.htmx-indicator {
 60	  opacity: 0;
 61	  transition: opacity 200ms ease-in;
 62	}
 63	
 64	.htmx-request .htmx-indicator {
 65	  opacity: 1;
 66	}
 67	
 68	.htmx-request.htmx-indicator {
 69	  opacity: 1;
 70	}
 71	
 72	/* Task card styling */
 73	.task-card {
 74	  transition: opacity 0.3s, transform 0.3s;
 75	}
 76	
 77	.htmx-swapping .task-card {
 78	  opacity: 0;
 79	  transform: translateX(-20px);
 80	}
 81	
 82	/* Title slot: stable container for the title input — swaps only ever replace its
 83	   innerHTML, never the h1 or the buttons beside it. */
 84	.title-slot {
 85	  flex: 1;
 86	  min-width: 200px;
 87	  display: flex;
 88	  align-items: center;
 89	  gap: 0.5rem;
 90	}
 91	
 92	.title-slot .title-input {
 93	  flex: 1;
 94	  min-width: 0;
 95	}
 96	
 97	/* Explore: compact actions table */
 98	.explore-actions {
 99	  width: 100%;
100	  border-collapse: collapse;
101	  font-size: 0.85rem;
102	  margin: 0.75rem 0;
103	}
104	
105	.explore-actions th,
106	.explore-actions td {
107	  text-align: left;
108	  vertical-align: top;
109	  padding: 0.25rem 0.5rem;
110	  border-bottom: 1px solid #e5e5e5;
111	}
112	
113	.explore-actions th {
114	  color: #666;
115	  font-weight: 600;
116	}
117	
118	.explore-actions td:first-child {
119	  white-space: nowrap;
120	  font-family: ui-monospace, monospace;
121	  color: #555;
122	}
123	
124	.explore-actions td:last-child {
125	  white-space: nowrap;
126	  text-align: right;
127	  color: #888;
128	  font-size: 0.78rem;
129	}
130	
131	.explore-actions pre {
132	  margin: 0;
133	  white-space: pre-wrap;
134	  word-break: break-word;
135	  font-size: 0.8rem;
136	}
137	
138	.explore-actions code {
139	  word-break: break-all;
140	}
141	
142	.trunc-marker {
143	  color: #a80;
144	}
145	
146	.explore-meta {
147	  color: #666;
148	  margin: 0.25rem 0;
149	}
150	
151	.explore-stale {
152	  background: #fff3cd;
153	  border: 1px solid #e0c878;
154	  border-radius: 6px;
155	  padding: 0.4rem 0.75rem;
156	  font-size: 0.9rem;
157	}
158	
159	.explore-summary {
160	  border-left: 3px solid #7ab;
161	  padding-left: 0.75rem;
162	  margin: 1rem 0;
163	}
164	
165	.explore-questions ul {
166	  margin: 0.25rem 0 0.5rem;
167	}
168	
169	/* Plan stage: Q&A form + final plan */
170	.plan-meta {
171	  color: #666;
172	  margin: 0.25rem 0;
173	}
174	
175	.plan-questions .plan-question {
176	  border: 1px solid #e0e0e0;
177	  border-radius: 6px;
178	  padding: 0.5rem 0.75rem;
179	  margin: 0.5rem 0;
180	}
181	
182	.plan-questions .plan-question legend {
183	  font-size: 0.9rem;
184	  font-weight: 600;
185	  padding: 0 0.25rem;
186	}
187	
188	.plan-options {
189	  display: flex;
190	  flex-direction: column;
191	  gap: 0.25rem;
192	}
193	
194	.plan-option {
195	  display: flex;
196	  align-items: center;
197	  gap: 0.4rem;
198	  margin: 0;
199	  font-weight: normal;
200	}
201	
202	.plan-option input {
203	  margin: 0;
204	}
205	
206	.plan-questions textarea {
207	  width: 100%;
208	  font-family: inherit;
209	}
210	
211	.plan-draft {
212	  margin: 0.75rem 0;
213	}
214	
215	.plan-final {
216	  border-left: 3px solid #7ab;
217	  padding-left: 0.75rem;
218	  margin: 1rem 0;
219	}
220	
221	/* Stage config screen */
222	.part-row {
223	  display: flex;
224	  align-items: center;
225	  gap: 0.75rem;
226	  padding: 0.5rem 0;
227	  border-bottom: 1px solid #e5e5e5;
228	}
229	
230	.part-row .part-label {
231	  flex: 0 0 16rem;
232	  font-weight: 600;
233	}
234	
235	.part-row code {
236	  color: #888;
237	  font-size: 0.8rem;
238	}
239	
240	.part-row select {
241	  flex: 1;
242	  min-width: 0;
243	  margin: 0;
244	}
245	
246	.stage-source {
247	  max-height: 32rem;
248	  overflow: auto;
249	  font-size: 0.78rem;
250	  background: #f6f6f6;
251	  border: 1px solid #e5e5e5;
252	  border-radius: 6px;
253	  padding: 0.75rem;
254	  white-space: pre;
255	}

 1	/**
 2	 * Minimal JS for htmx interactions
 3	 * Most functionality is handled by htmx attributes in HTML
 4	 */
 5	
 6	(function () {
 7	  // Auto-focus the content textarea when a prompt row switches to edit mode
 8	  document.body.addEventListener('htmx:afterSwap', function (evt) {
 9	    const editor = evt.target.querySelector('textarea[name="content"]:not([readonly])');
10	    if (editor) {
11	      editor.focus();
12	    }
13	  });
14	
15	  // Global htmx error handling
16	  document.body.addEventListener('htmx:responseError', function (evt) {
17	    console.error('htmx error:', evt.detail);
18	  });
19	})();

